'use client'

import { motion } from 'framer-motion'
import { Button } from '@/components/ui/button'
import { fadeInUp } from '@/lib/animations'
import { useTheme } from 'next-themes'
import { cn } from '@/lib/utils'

export interface Answer {
  id: string
  text_ar: string
  text_en: string
  type_scores: Record<string, number>
}

export interface Question {
  id: string
  question_ar: string
  question_en: string
  description_ar?: string
  description_en?: string
  answers: Answer[]
  order: number
}

interface QuestionCardProps {
  question: Question
  selectedAnswerId?: string
  onAnswerSelect: (answerId: string) => void
  isLoading?: boolean
}

export function QuestionCard({
  question,
  selectedAnswerId,
  onAnswerSelect,
  isLoading = false,
}: QuestionCardProps) {
  const { theme } = useTheme()
  const isEnglish = false // TODO: Get from i18n context
  
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      exit={{ opacity: 0, scale: 1.05 }}
      transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
      className="space-y-12"
    >
      {/* Question Header */}
      <div className={cn("space-y-6 text-center", isEnglish ? "lg:text-left" : "lg:text-right")}>
        <motion.div 
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-primary/10 text-primary border border-primary/20 text-sm font-black uppercase tracking-widest"
        >
          {isEnglish ? `Question ${question.order || 1}` : `السؤال رقم ${question.order || 1}`}
        </motion.div>
        <h2 className="text-4xl md:text-5xl lg:text-6xl font-black leading-[1.15] text-foreground tracking-tight">
          {isEnglish ? question.question_en : question.question_ar}
        </h2>
        {(isEnglish ? question.description_en : question.description_ar) && (
          <p className="text-xl md:text-2xl text-muted-foreground font-bold opacity-80 max-w-3xl leading-relaxed">
            {isEnglish ? question.description_en : question.description_ar}
          </p>
        )}
      </div>

      {/* Answers Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
        {question.answers.map((answer, index) => (
          <motion.button
            key={answer.id}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
            onClick={() => onAnswerSelect(answer.id)}
            disabled={isLoading}
            className={cn(
              "group relative w-full p-8 rounded-[2rem] border-2 transition-all duration-500 overflow-hidden",
              isEnglish ? "text-left" : "text-right",
              selectedAnswerId === answer.id
                ? "border-primary bg-primary/5 shadow-2xl shadow-primary/10"
                : "border-border/60 hover:border-primary/40 bg-card/40 backdrop-blur-xl hover:bg-card/80 hover:shadow-xl"
            )}
          >
            {/* Background Accent */}
            <div className={cn(
              "absolute inset-0 bg-gradient-to-br from-primary/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500",
              selectedAnswerId === answer.id && "opacity-100"
            )} />
            
            <div className={cn("relative flex items-center justify-between gap-6", isEnglish && "flex-row-reverse")}>
              <div className="flex-1 space-y-1">
                <span className={cn(
                  "block text-xl md:text-2xl font-black transition-all duration-300",
                  selectedAnswerId === answer.id ? "text-primary translate-x-1" : "text-foreground"
                )}>
                  {isEnglish ? answer.text_en : answer.text_ar}
                </span>
              </div>
              
              {/* Radio-style indicator */}
              <div className={cn(
                "w-10 h-10 rounded-full border-4 flex items-center justify-center transition-all duration-500 shrink-0",
                selectedAnswerId === answer.id 
                  ? "border-primary bg-primary shadow-[0_0_20px_rgba(79,70,229,0.4)] scale-110" 
                  : "border-border/80 group-hover:border-primary/50 group-hover:scale-105"
              )}>
                {selectedAnswerId === answer.id && (
                  <motion.div 
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    className="w-3 h-3 bg-white rounded-full"
                  />
                )}
              </div>
            </div>

            {/* Selection highlight bar */}
            {selectedAnswerId === answer.id && (
              <motion.div 
                layoutId="answer-active-bar"
                className={cn("absolute top-0 bottom-0 w-2 bg-primary", isEnglish ? "left-0" : "right-0")}
              />
            )}
          </motion.button>
        ))}
      </div>
    </motion.div>
  )
}
